-- ============================================
-- FoodAdvisor OSM 成都餐饮数据导入
-- 来源: OpenStreetMap (overpass-turbo)
-- OSM 时间戳: 2026-07-17T02:42:56Z
-- 生成时间: 2026-07-18T12:01:09.738426
-- 共 2285 条商家记录
--
-- 映射说明:
--   amenity → category (餐厅/咖啡厅/快餐/网吧)
--   name 缺失 → '未命名' + category
--   address 缺失 → '成都市'
--   cuisine / phone / description → 有则填入
--   rating / average_price / region_code 等 → NULL（OSM 无此数据）
-- ============================================

BEGIN;

-- ============================================
-- 1. 导入任务记录
-- ============================================
VALUES ('MERCHANT', 'chengdu_restaurants.geojson', 'SUCCESS', 2285, 2285, 0, 1, NOW(), NOW());

-- ============================================
-- 2. 创建临时导入表
-- ============================================
CREATE TEMP TABLE _osm_import (
    osm_id       TEXT,
    name         TEXT,
    category     TEXT,
    cuisine      TEXT,
    address      TEXT,
    longitude    NUMERIC(10,6),
    latitude     NUMERIC(10,6),
    phone        TEXT,
    description  TEXT,
    raw_data     JSONB
);


-- ============================================
-- 3. 从临时表批量写入 merchants
-- ============================================
-- 修正序列值：种子数据手动指定了 id，序列未自动推进
SELECT setval('merchants_id_seq', (SELECT COALESCE(MAX(id), 0) FROM merchants));

    merchant_code, name, category, cuisine,
    rating, average_price, review_count,
    address, region_code,
    longitude, latitude,
    phone, contact_email, description, cover_image_url,
    environment_tags, platform_status, operation_status
)
SELECT
    osm_id, name, category, cuisine,
    NULL AS rating, NULL AS average_price, 0 AS review_count,
    address, NULL AS region_code,
    longitude, latitude,
    phone, NULL AS contact_email, description, NULL AS cover_image_url,
    '[]'::jsonb AS environment_tags, 'ACTIVE' AS platform_status, 'OPERATING' AS operation_status
FROM _osm_import
ON CONFLICT (merchant_code) DO NOTHING;

-- ============================================
-- 4. 导入明细（关联 merchants.id）
-- ============================================
SELECT
    (SELECT id FROM import_tasks WHERE original_filename = 'chengdu_restaurants.geojson' ORDER BY id DESC LIMIT 1),
    ROW_NUMBER() OVER (),
    o.osm_id,
    o.raw_data,
    'SUCCESS',
    m.id
FROM _osm_import o
JOIN merchants m ON m.merchant_code = o.osm_id;

-- ============================================
-- 5. 清理临时表
-- ============================================
DROP TABLE _osm_import;

COMMIT;

-- 导入完成: 2285 条记录